from collections import deque

class Solution:
    def networkBecomesIdle(self, edges, patience):
        n = len(patience)
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        dist = [-1] * n
        dist[0] = 0
        q = deque([0])
        while q:
            u = q.popleft()
            for v in adj[u]:
                if dist[v] == -1:
                    dist[v] = dist[u] + 1
                    q.append(v)
        ans = 0
        for i in range(1, n):
            rt = 2 * dist[i]
            p = patience[i]
            if rt <= p:
                last_sent = 0
            else:
                cnt = (rt - 1) // p
                last_sent = cnt * p
            ans = max(ans, last_sent + rt + 1)
        return ans

